const src = $json.body && typeof $json.body === 'object' ? { ...$json, ...$json.body } : $json;

const expectedIngressToken = $env.N8N_INGRESS_TOKEN || '';
const authHeader = String(src.headers?.authorization || src.headers?.Authorization || '').trim();
if (expectedIngressToken) {
  if (!authHeader.startsWith('Bearer ') || authHeader.slice(7) !== expectedIngressToken) {
    throw new Error('Unauthorized webhook ingress token');
  }
}

function toText(v) {
  if (v == null) return '';
  if (typeof v === 'string') return v;
  if (Array.isArray(v)) return v.map(toText).join(' ');
  if (typeof v === 'object') return toText(v.text || v.mensagem || v.content || v.body || '');
  return String(v);
}

function pickCliente(input) {
  if (!input) return { nome: 'Cliente', telefone: '' };
  if (typeof input === 'string') return { nome: input.trim() || 'Cliente', telefone: '' };
  return {
    nome: String(input.nome || input.name || input.pushName || 'Cliente').trim() || 'Cliente',
    telefone: String(input.telefone || input.phone || input.phoneNumber || '').trim(),
  };
}

const mensagem = toText(src.mensagem || src.mensagens || src.message || src.messages || '').replace(/\s+/g, ' ').trim();
if (!mensagem) throw new Error('Mensagem vazia no payload');

const clienteObj = pickCliente(src.cliente || src.customer || src.contact || null);
const clienteTelefone = String(src.cliente_telefone || src.telefone || src.phone || src.contact?.phoneNumber || clienteObj.telefone || src.from || '').replace(/\D/g, '');

const ticketId = String(src.ticket_id || src.ticket?.id || src.conversation_id || src.conversationId || '').trim();

return [{
  json: {
    ticket_id: ticketId,
    cliente: {
      nome: clienteObj.nome,
      telefone: clienteTelefone,
    },
    cliente_nome: clienteObj.nome,
    cliente_telefone: clienteTelefone,
    mensagens: mensagem,
    canal: 'whatsapp',
    tecnico: String(src.tecnico || src.assignee || 'n8n').trim(),
    data_evento: src.data_evento || src.timestamp || new Date().toISOString(),
    organization_id: src.organization_id || src.organizationId || null,
    event_id: src.event_id || `evt-${Date.now()}`,
    raw: src
  }
}];

const src = $input.first().json || {};
const respostaEnviada = Boolean(src.resposta_sugerida || src.resposta);
return [{ json: { status: 'sucesso', ticket_id: $('2. Normalizar Dados').item.json.ticket_id || null, atendimento_id: $('5.1 Ingestao Retornou OK?').item.json.atendimento_id || null, resposta_enviada: respostaEnviada, timestamp: new Date().toISOString() } }];
